const SUB_CATEGORIES = [FAIRY, ANIMALS, FRUITS, SCHOOL, FOOD, SPORTS];

const MIXED = {
  id: 'mixed',
  name: '大杂烩',
  pairs: SUB_CATEGORIES.flatMap((category) => category.pairs),
};

const WORD_BANK = [MIXED, ...SUB_CATEGORIES];

function getCategorySummaries() {
  return WORD_BANK.map(({ id, name, pairs }) => ({
    id,
    name,
    pairCount: pairs.length,
  }));
}

function findCategoryById(categoryId) {
  return WORD_BANK.find((category) => category.id === categoryId);
}

module.exports = {
  WORD_BANK,
  findCategoryById,
  getCategorySummaries,
};
